import http from "node:http";
import https from "node:https";
import zlib from "node:zlib";
import { URL } from "node:url";

const PREFIX = "/atlas/";

function encode(url) {
  return Buffer.from(encodeURIComponent(url))
    .toString("base64")
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=/g, "");
}

function decode(encoded) {
  const padded = encoded + "=".repeat((4 - (encoded.length % 4)) % 4);
  return decodeURIComponent(
    Buffer.from(padded.replace(/-/g, "+").replace(/_/g, "/"), "base64").toString("utf8")
  );
}

function rewriteUrl(url, base) {
  if (!url) return url;
  const trimmed = url.trim();
  if (
    trimmed.startsWith("javascript:") ||
    trimmed.startsWith("data:") ||
    trimmed.startsWith("blob:") ||
    trimmed.startsWith("#") ||
    trimmed.startsWith("mailto:") ||
    trimmed.startsWith("tel:") ||
    trimmed.startsWith("about:") ||
    trimmed.startsWith(PREFIX)
  ) {
    return url;
  }
  try {
    const resolved = base ? new URL(trimmed, base).href : new URL(trimmed).href;
    return PREFIX + encode(resolved);
  } catch {
    return url;
  }
}

function rewriteCss(css, base) {
  if (!css) return css;
  return css
    .replace(/url\(\s*(['"]?)([^'")]+)\1\s*\)/gi, (_, quote, url) => {
      return `url(${quote}${rewriteUrl(url.trim(), base)}${quote})`;
    })
    .replace(/@import\s+(['"])([^'"]+)\1/gi, (_, quote, url) => {
      return `@import ${quote}${rewriteUrl(url, base)}${quote}`;
    })
    .replace(/@import\s+url\(\s*(['"]?)([^'")]+)\1\s*\)/gi, (_, quote, url) => {
      return `@import url(${quote}${rewriteUrl(url.trim(), base)}${quote})`;
    });
}

const URL_ATTRS = new Set([
  "href", "src", "action", "formaction", "poster", "data",
  "background", "ping", "manifest", "xlink:href",
]);
const SRCSET_ATTRS = new Set(["srcset", "imagesrcset"]);

function rewriteSrcset(val, base) {
  return val.split(",").map(part => {
    const m = part.trim().match(/^(\S+)(\s.*)?$/);
    return m ? rewriteUrl(m[1], base) + (m[2] || "") : part;
  }).join(", ");
}

function processAttrs(attrs, base) {
  return attrs.replace(
    /(\s+)([\w:-]+)(\s*=\s*)(["'])([\s\S]*?)\4/g,
    (m, sp, name, eq, q, val) => {
      const n = name.toLowerCase();
      if (n === "integrity") return "";
      if (n === "style") return sp + name + eq + q + rewriteCss(val, base) + q;
      if (URL_ATTRS.has(n)) return sp + name + eq + q + rewriteUrl(val.trim(), base) + q;
      if (SRCSET_ATTRS.has(n)) return sp + name + eq + q + rewriteSrcset(val, base) + q;
      return m;
    }
  );
}

function findTagEnd(html, from) {
  let q = 0;
  for (let i = from; i < html.length; i++) {
    const c = html.charCodeAt(i);
    if (q) { if (c === q) q = 0; }
    else if (c === 34 || c === 39) { q = c; }
    else if (c === 62) return i;
  }
  return -1;
}

const INJECT = (base) =>
  `<script>!function(){var c=window.__atlas={prefix:"/atlas/",base:${JSON.stringify(base)},` +
  `encode:function(u){try{return btoa(encodeURIComponent(u)).replace(/\\+/g,"-").replace(/\\//g,"_").replace(/=/g,"")}catch(e){return u}},` +
  `decode:function(e){try{var p=e+"=".repeat((4-e.length%4)%4);return decodeURIComponent(atob(p.replace(/-/g,"+").replace(/_/g,"/")))}catch(e){return e}},` +
  `rewrite:function(u,b){if(!u)return u;var t=String(u).trim();` +
  `if(/^(javascript:|data:|blob:|#|mailto:|tel:|about:|\\/atlas\\/)/.test(t))return u;` +
  `try{var r=b?new URL(t,b).href:new URL(t).href;return"/atlas/"+c.encode(r)}catch(e){return u}}}();</script>` +
  `<script src="/atlas.client.js"></script>`;

function rewriteHtml(html, base) {
  const out = [];
  let i = 0;
  let inScript = false;
  let inStyle = false;
  let styleBuf = "";
  let injected = false;

  while (i < html.length) {
    if (html.charCodeAt(i) !== 60) {
      const next = html.indexOf("<", i);
      if (next === -1) {
        (inStyle ? (styleBuf += html.slice(i)) : out.push(html.slice(i)));
        break;
      }
      inStyle ? (styleBuf += html.slice(i, next)) : out.push(html.slice(i, next));
      i = next;
      continue;
    }

    if (html.startsWith("<!--", i)) {
      const end = html.indexOf("-->", i + 4);
      if (end === -1) { out.push(html.slice(i)); break; }
      out.push(html.slice(i, end + 3));
      i = end + 3;
      continue;
    }

    if (html.charCodeAt(i + 1) === 33) {
      const end = html.indexOf(">", i + 2);
      if (end === -1) { out.push(html.slice(i)); break; }
      out.push(html.slice(i, end + 1));
      i = end + 1;
      continue;
    }

    const tagEnd = findTagEnd(html, i + 1);
    if (tagEnd === -1) { out.push(html.slice(i)); break; }

    const inner = html.slice(i + 1, tagEnd);
    const nm = inner.match(/^(\/?)([\w-]+)/);
    const tag = nm?.[2]?.toLowerCase() ?? "";
    const isClose = nm?.[1] === "/";

    if (inScript) {
      if (isClose && tag === "script") { inScript = false; out.push("</script>"); }
      else out.push(html.slice(i, tagEnd + 1));
      i = tagEnd + 1;
      continue;
    }

    if (inStyle) {
      if (isClose && tag === "style") {
        inStyle = false;
        out.push(rewriteCss(styleBuf, base));
        styleBuf = "";
        out.push("</style>");
      } else {
        styleBuf += html.slice(i, tagEnd + 1);
      }
      i = tagEnd + 1;
      continue;
    }

    if (isClose) {
      if (!injected && tag === "head") { out.push(INJECT(base)); injected = true; }
      out.push(`</${tag}>`);
      i = tagEnd + 1;
      continue;
    }

    if (tag === "meta") {
      if (/content-security-policy/i.test(inner)) { i = tagEnd + 1; continue; }
    }

    if (tag === "base") {
      const m = inner.match(/\shref\s*=\s*(["'])([^"']*)\1/i);
      if (m) try { base = new URL(m[2], base).href; } catch {}
    }

    const attrStr = inner.slice(nm?.[0]?.length ?? 0);
    const selfClose = /\/\s*$/.test(attrStr);
    const attrs = processAttrs(attrStr.replace(/\/\s*$/, ""), base);
    out.push(`<${tag}${attrs}${selfClose ? " /" : ""}>`);

    if (tag === "head" && !injected) { out.push(INJECT(base)); injected = true; }
    if (tag === "script") inScript = true;
    if (tag === "style") inStyle = true;

    i = tagEnd + 1;
  }

  if (!injected) out.unshift(INJECT(base));
  return out.join("");
}

function rewriteJs(js, _base) {
  if (!js) return js;
  return js;
}

const CACHE = new Map();
let cacheBytes = 0;
const CACHE_MAX_BYTES = 64 * 1024 * 1024;
const CACHE_TTL = 5 * 60 * 1000;
const CACHE_ENTRY_MAX = 4 * 1024 * 1024;
const CACHEABLE_CT = /^(image\/|font\/|text\/css|application\/javascript|text\/javascript)/;

function cacheGet(key) {
  const e = CACHE.get(key);
  if (!e) return null;
  if (Date.now() > e.exp) { cacheBytes -= e.body.length; CACHE.delete(key); return null; }
  return e;
}

function cacheSet(key, status, headers, body) {
  if (body.length > CACHE_ENTRY_MAX) return;
  if (CACHE.has(key)) { cacheBytes -= CACHE.get(key).body.length; CACHE.delete(key); }
  while (cacheBytes + body.length > CACHE_MAX_BYTES && CACHE.size) {
    const oldest = CACHE.keys().next().value;
    cacheBytes -= CACHE.get(oldest).body.length;
    CACHE.delete(oldest);
  }
  cacheBytes += body.length;
  CACHE.set(key, { status, headers, body, exp: Date.now() + CACHE_TTL });
}

const httpAgent = new http.Agent({ keepAlive: true, maxSockets: 256, scheduling: "fifo" });
const httpsAgent = new https.Agent({ keepAlive: true, maxSockets: 256, rejectUnauthorized: false, scheduling: "fifo" });

const DROP_REQ = new Set([
  "host", "origin", "connection", "keep-alive", "te", "trailer",
  "upgrade", "proxy-authorization", "transfer-encoding", "accept-encoding",
]);

const DROP_RES = new Set([
  "connection", "keep-alive", "transfer-encoding", "te", "trailer",
  "upgrade", "content-encoding", "content-security-policy",
  "content-security-policy-report-only", "x-frame-options",
  "strict-transport-security",
]);

const BASE_HEADERS = {
  "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
  "accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8",
  "accept-language": "en-US,en;q=0.5",
  "accept-encoding": "identity",
};

const MAX_REDIRECTS = 10;

function rawFetch(targetUrl, options, redirectCount = 0) {
  return new Promise((resolve, reject) => {
    const parsed = new URL(targetUrl);
    const isHttps = parsed.protocol === "https:";
    const lib = isHttps ? https : http;

    const req = lib.request({
      hostname: parsed.hostname,
      port: parsed.port || (isHttps ? 443 : 80),
      path: parsed.pathname + parsed.search,
      method: options.method || "GET",
      headers: options.headers || {},
      agent: isHttps ? httpsAgent : httpAgent,
      timeout: 20000,
    }, (res) => {
      const { statusCode: status, headers } = res;
      const location = headers["location"];

      if (status >= 300 && status < 400 && location && redirectCount < MAX_REDIRECTS) {
        res.resume();
        resolve(rawFetch(new URL(location, targetUrl).href, options, redirectCount + 1));
        return;
      }

      resolve({ status, headers, body: res, url: targetUrl });
    });

    req.on("error", reject);
    req.on("timeout", () => { req.destroy(); reject(new Error("Request timed out")); });

    if (options.body) req.write(options.body);
    req.end();
  });
}

function decompressStream(stream, encoding) {
  const enc = (encoding || "").toLowerCase();
  if (enc === "gzip" || enc === "x-gzip") return stream.pipe(zlib.createGunzip());
  if (enc === "deflate") return stream.pipe(zlib.createInflate());
  if (enc === "br") return stream.pipe(zlib.createBrotliDecompress());
  return stream;
}

function collectStream(stream) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    stream.on("data", (c) => chunks.push(c));
    stream.on("end", () => resolve(Buffer.concat(chunks)));
    stream.on("error", reject);
  });
}

function getReqBody(req) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on("data", (c) => chunks.push(c));
    req.on("end", () => resolve(Buffer.concat(chunks)));
    req.on("error", reject);
  });
}

function buildOutHeaders(resHeaders) {
  const out = { "cross-origin-resource-policy": "cross-origin" };
  for (const [k, v] of Object.entries(resHeaders)) {
    if (!DROP_RES.has(k.toLowerCase())) out[k] = v;
  }
  return out;
}

